import UIKit
import Alamofire

class TradeViewController: UIViewController {
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Setup UI
        setupUI()
    }
    
    private func setupUI() {
        buyButton.layer.cornerRadius = 8
        sellButton.layer.cornerRadius = 8
        
        stockSymbolTextField.borderStyle = .roundedRect
        quantityTextField.borderStyle = .roundedRect
    }
    
    @IBAction func buyButtonTapped(_ sender: UIButton) {
        executeTrade(action: "buy")
    }
    
    @IBAction func sellButtonTapped(_ sender: UIButton) {
        executeTrade(action: "sell")
    }
    
    private func executeTrade(action: String) {
        guard let stockSymbol = stockSymbolTextField.text, !stockSymbol.isEmpty,
              let quantityString = quantityTextField.text, let quantity = Int(quantityString),
              quantity > 0 else {
            showAlert(message: "Please enter valid stock symbol and quantity.")
            return
        }
        
        let parameters: [String: Any] = [
            "action": action,
            "stockSymbol": stockSymbol,
            "quantity": quantity
        ]
        
        AF.request("https://api.example.com/trade", method: .post, parameters: parameters, encoding: JSONEncoding.default).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let json = value as? [String: Any], let success = json["success"] as? Bool, success {
                    self.showAlert(message: "Trade executed successfully.")
                } else {
                    self.showAlert(message: "Failed to execute trade.")
                }
            case .failure(let error):
                print("Error executing trade: \(error)")
                self.showAlert(message: "An error occurred. Please try again later.")
            }
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Trade Result", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}